// Create the unified word set
export const WORD_SET = new Set<string>()

// Add all categories
Object.values(CATEGORIES).forEach(list => {
  list.forEach(w => WORD_SET.add(w.toLowerCase()))
})

// Add common vocabulary
COMMON_WORDS.forEach(word => {
  WORD_SET.add(word.toLowerCase())
})

// Helper to determine if a word is in our dictionary
export function isValidWord(word: string): boolean {
  if (!word || word.length < 3) return false
  return WORD_SET.has(word.toLowerCase())
}

// Helper to check if a word belongs to any special category
export function getWordCategory(word: string): string | null {
  const w = word.toLowerCase()
  for (const [category, words] of Object.entries(CATEGORIES)) {
    if (words.includes(w)) {
      return category
    }
  }
  return null
}
